# Shape module with class inheritance

class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    def area(self) -> float:
        return 0.0

    def describe(self) -> str:
        return "Shape " + self.name

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, name: str, w: float, h: float):
        super().__init__(name)
        self.width = w
        self.height = h

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return "Rectangle " + self.name

class Square(Rectangle):
    def __init__(self, name: str, side: float):
        super().__init__(name, side, side)

    @override
    def describe(self) -> str:
        side_str = str(self.width)
        return "Square " + self.name + " side=" + side_str

